import { Configuration } from "model/configuration";
import { pregenSystem } from "model/system";
import { randomTarget, Target } from "model/target";
import { System } from "model/system";
import { range } from "model/math";

const LOCALSTORAGE_KEY = "BigShotData";
const CURRENT_SCHEMA_ID = 1;

export interface State {
    schemaId: number;
    configuration: Configuration;
    system: System;
    bounties: Target[];
}

const zero: State = {
    schemaId: CURRENT_SCHEMA_ID,
    configuration: {
        isBackgroundAnimated: true,
        showBountiesInCcOnBoard: false,
        showBountyCutOnBoard: false,
        showPersonalGrudgesOnBoard: true,
    },
    system: pregenSystem,
    bounties: range(10).map(id => ({ ...randomTarget(pregenSystem), id: id.toString() })),
};

const maybeSerialized = localStorage.getItem(LOCALSTORAGE_KEY);
const maybeDeserialized = maybeSerialized ? JSON.parse(maybeSerialized) : null;
const maybeSchemaId = maybeDeserialized?.schemaId;

let state = zero;
if (maybeSchemaId === CURRENT_SCHEMA_ID) {
    state = maybeDeserialized;
} else {
    localStorage.setItem(LOCALSTORAGE_KEY, JSON.stringify(state));
}

export function updateState(update: Partial<State>) {
    state = { ...state, ...update};
    localStorage.setItem(LOCALSTORAGE_KEY, JSON.stringify(state));
}

export function getState(): State {
    return {...state};
}