export function randomInt(max: number): number {
    return Math.floor(Math.random() * max);
}

export function randomDiceroll(diceCount: number, faceCount: number) {
    return range(diceCount).map(_ => randomInt(faceCount) + 1).reduce((a,b)=> a+b);
}

export function range(max: number): number[] {
    return [...new Array(max).keys()];
}

export function randomChoice<A>(table: A[]): A {
    return table[randomInt(table.length)];
}