import { randomChoice, randomInt } from './model/math';
import star1 from './assets/star1.png'
import star2 from './assets/star2.png';
import star3 from './assets/star3.png';
import star4 from './assets/star4.png';


const stars: HTMLElement[] = [];
let elapsed = 0;
let timer: number|null = null;

export function setUp() {
    if (!stars.length) {
        for (let i = 0; i < 30; i ++) {
          const el = window.document.createElement('img');
          stars.push(el);   
          const randomSize = randomChoice([1, 1, 1, 1, 1, 1, 1, 2, 2, 2, 3, 4]);
          const randomTop = randomInt(window.innerHeight) - 256;
          const randomLeft = randomInt(window.innerWidth);
          el.src = [star1, star2, star3, star4][randomSize-1];
          el.style.position = 'absolute';
          el.style.top = `${randomTop}px`; 
          el.style.left = `${randomLeft}px`; 
          //el.style.overflow = 'hidden';
          el.style.zIndex = '-100';
          window.document.body.insertAdjacentElement('beforeend', el);
        }
      }
}

export function disable() {
    if (timer != null) {
        clearInterval(timer);
    }
    timer = null;
}

export function animate() {
    if (timer != null) {
      clearInterval(timer);
    }
    timer = setInterval(function () {
    elapsed = elapsed + 1;
    window.document.body.style.backgroundPositionX = `${-(elapsed%1920)}px, ${-(Math.round(elapsed/7)%1920)}px, ${-(Math.round(elapsed/9)%1920)}px`;
    if (elapsed % 13 === 0) {
      for (let el of stars) {
          const left = parseInt(el.style.left.substring(0, el.style.left.length - 2));
          let newLeft = left - 1;
          if (newLeft < - 16) {
            const randomTop = randomInt(window.innerHeight) - 256;
            el.style.top = `${randomTop}px`; 
            newLeft = window.innerWidth + 16;
          }
          el.style.left = `${newLeft}px`; 
      } 
      }
    }, 250) as any;
};