import { Target } from "model/target";
import mugshotOrganic from 'assets/mugshot-organic.png';
import mugshotBeast from 'assets/mugshot-beast.png';
import mugshotRobot from 'assets/mugshot-robot.png';


export function formatPercentage(amount: number) {
    return `${Math.round(amount * 100)}%`;
  }
  
export   function formatPortrait(target: Target) {
    switch (target.race) {
        case "Organic":
        case "Mutant":
        return mugshotOrganic;
        case "Beast":
        return mugshotBeast;
        case "Robot":
        case "Droid":
        return mugshotRobot;
    }
}


export function formatCurrency(currencySymbol: string) {
  switch (currencySymbol) {
    case ' ҉':
      return currencySymbol + ' ';
    case 'ண':
      return (<span style={{ ['fontSize' as any]: 'x-small'}} >ண</span>);
    case 'ဩ':
        return (<span style={{ ['fontSize' as any]: 'x-small'}} >ဩ</span>);
    case 'ੳ':
      return (<span style={{ ['fontSize' as any]: 'x-small'}} >ੳ</span>);
    default:
        return currencySymbol;
  }
}

