export function formatBounty(amount: number, currencySymbol: string) {
  const currencyFormatted = formatCurrency(currencySymbol);
  const amountFormatted = amount.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  return <span>{currencyFormatted}{amountFormatted}</span>;
}
