import 'core-js/es/object/group-by';
import { useState } from "react";
import { Link } from 'react-router-dom';
import { formatBounty, formatPortrait } from 'formatting';
import { bountiesRepo } from 'model/repo';
import { getState } from 'state';
import { Configuration } from 'model/configuration';
import { Target } from 'model/target';


export function Index() {
  const configuration = getState().configuration;
  const [bounties, setBounties] = useState(bountiesRepo.getAll())
  function resetBounties() {
    bountiesRepo.reset();
    setBounties(bountiesRepo.getAll())
  }
  const targetsByRow = {...Object.groupBy(bounties, (_, i) => Math.floor(i / 5).toString())};
  return (
    <div>
      <div className="card-bottom">
        <p>Welcome back, Bounty Hunter!</p>
        <p>Big Shot is the biggest electronic bounty board system in our solar system.</p>
        <p>All bounties are nominal. Additional costs may apply.</p>
        <p>Select a bounty to learn more.</p>
        <p>If none of the bounties interests you, you can use our interdimensional portal to try your luck in another universe.
          Beware, it is one-way only.</p>
        <div className="commandsPane">
          <div className="expand"/>
          <button onClick={resetBounties}>Warp to a parallel universe</button>
        </div>
      </div>

      {
        Object.keys(targetsByRow).map((k, i) => {
          return (<div className="row" key={"r" + i}>
            {
              targetsByRow[k]!.map((t, j) => {
                return (
                  <div className="card bounty-small" key={"r" + i + "c" + j}>
                    <Link to={`/bounty/${t.id}`}>
                    <div className="header">{t.usedName}</div>
                    <img src={formatPortrait(t)} />
                    { formatBountyLine(t, configuration) }
                    </Link>
                </div>
                )
              })
            }
          </div>);
        })
      }
    </div>
  );
}

function formatBountyLine(target: Target, configuration: Configuration) {
  if (configuration.showPersonalGrudgesOnBoard && target.isPersonalGrudge) {
    return (<div className="grudge">PERSONAL GRUDGE</div>);
  }
  const amount = Math.floor(Math.floor(target.bounty * (configuration.showBountyCutOnBoard ? target.rewardCut : 1)) *(configuration.showBountiesInCcOnBoard ? target.lastSeenOnPlanet.currency.rateToCc : 1));
  const currency = configuration.showBountiesInCcOnBoard ? 'CC' : target.lastSeenOnPlanet.currency.symbol;
  
  return (<div>{formatBounty(amount, currency)}</div>);
}