    getAll() {
        return getState().bounties;
    }

    getById(id: string) {
        return getState().bounties.find(b => b.id === id);
    }

    nextId(id: string): string|null {
        const all =  getState().bounties;
        const idx = all.findIndex(b => b.id === id);
        const nextIdx = idx + 1;
        if (nextIdx === all.length) {
            return null;
        }
        const nextId = all[nextIdx].id;
        return nextId;
    }

    prevId(id: string): string|null {
        const all =  getState().bounties;
        const idx = all.findIndex(b => b.id === id);
        const prevIdx = idx - 1;
        if (prevIdx < 0) {
            return null;
        }
        const prevId = all[prevIdx].id;
        return prevId;
    }

    reset() {
        const system = getState().system;
        const bounties = range(10).map(id => ({ ...randomTarget(system), id: id.toString() }));
        updateState({ bounties, });
    }

