import { animate, disable } from "background";
import { useState } from "react";
import { getState, updateState } from "state";

export function Settings() {
  const [viewState, setViewState] = useState(getState().configuration);

  function backgroundAnimatedChanged() {
    const newViewState = { ...viewState, isBackgroundAnimated: !viewState.isBackgroundAnimated, };
    if (newViewState.isBackgroundAnimated) {
      animate();
    } else {
      disable();
    }
    updateState({ configuration: newViewState });
    setViewState(newViewState);
  }

  function showBountiesInCcOnBoardChanged() {
    const newViewState = { ...viewState, showBountiesInCcOnBoard: !viewState.showBountiesInCcOnBoard, };
    updateState({ configuration: newViewState });
    setViewState(newViewState);
  }

  function showBountyCutOnBoardChanged() {
    const newViewState = { ...viewState, showBountyCutOnBoard: !viewState.showBountyCutOnBoard, };
    updateState({ configuration: newViewState });
    setViewState(newViewState);
  }

  function showPersonalGrudgesOnBoardChanged() {
    const newViewState = { ...viewState, showPersonalGrudgesOnBoard: !viewState.showPersonalGrudgesOnBoard, };
    updateState({ configuration: newViewState });
    setViewState(newViewState);
  }

  return (
    <div>
      <div className="card-bottom">
        <h2>General</h2>
        <div>
          <input type="checkbox" id="is-background-animated" checked={viewState.isBackgroundAnimated} onChange={backgroundAnimatedChanged} />
          <label htmlFor="is-background-animated">Animate the background</label>
        </div>
        <h2>Bounty board</h2>
        <div>
          <input type="checkbox" id="show-bounties-in-cc"  checked={viewState.showBountiesInCcOnBoard} onChange={showBountiesInCcOnBoardChanged} />
          <label htmlFor="show-bounties-in-cc">Convert local currency to CC</label>
        </div>
        <div>
          <input type="checkbox" id="show-bounty-cut"   checked={viewState.showBountyCutOnBoard} onChange={showBountyCutOnBoardChanged}/>
          <label htmlFor="show-bounty-cut">Show just the cut instead of total bounty</label>
        </div>
        <div>
          <input type="checkbox" id="show-personal-grudges"  checked={viewState.showPersonalGrudgesOnBoard} onChange={showPersonalGrudgesOnBoardChanged} />
          <label htmlFor="show-personal-grudges">Highlight personal grudges</label>
        </div>
      </div>
    </div>
  );
}
