import React from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';

import { animate, setUp } from 'background';
import { getState } from 'state';
import logo from 'assets/logo.png';

export function AppLayout() {
  React.useEffect(() => {
    setUp();
    if (getState().configuration.isBackgroundAnimated) {
      animate();
    }
  });
  const pathname = useLocation().pathname;
  return (
        <div className='body-inner'>
          <div className="card-top">
            <div className='header'>
              <h1><img src={logo} /> Big Shot Bounty Board System</h1>
            </div>
            <div className='menu'>
              <div className={pathname === '/' || pathname.startsWith('/bounty') ? 'active' : ''}>
                <Link to="/">Bounties</Link>
            </div>
              <div className={pathname === '/about' ? 'active' : ''}>
                <Link to="/about">About</Link>
            </div>
              <div className={pathname === '/settings' ? 'active' : ''}>
                <Link to="/settings">Settings</Link>
              </div>
            </div>
          </div>
          <div className='content'>
            <Outlet />
          </div>
          <div className="versionInfo">env: {process.env.NODE_ENV} ver: {process.env.REACT_APP_FE_VERSION || '0.0.0.0'}<br/>made in year 10,0025 by anon</div>
        </div>
  );
}
