function setUpTooltip(elementId: string, tooltipId: string) {
  const element = window.document.getElementById(elementId)!;
  const tooltip = window.document.getElementById(tooltipId)!;
  const popper = createPopper(element, tooltip, {
    placement: 'right-end',
    modifiers: [
      {
        name: 'offset',
        options: {
          offset: [8, 8],
        },
      },
    ],
  });
  function show() {
    tooltip.setAttribute('data-show', '');
    popper.update();
  }
  function hide() {
    tooltip.removeAttribute('data-show');
  }
  const showEvents = ['mouseenter', 'focus'];
  const hideEvents = ['mouseleave', 'blur'];
  showEvents.forEach((event) => {
    element.addEventListener(event, show);
  });
  hideEvents.forEach((event) => {
    element.addEventListener(event, hide);
  });
}

