function formatFees(feeIds: number[]) {
  return feeIds.map(id => fees.find(f => f.id === id)).map(f => f!.name).join(', ');
}

function formatLaws(lawIds: number[]) {
  return lawIds.map(id => laws.find(f => f.id === id)).map(f => f!.description).join(', ');
}


function formatPolitic(politic: number): string {
  const description = politic < 5 ? 'liberal'
    : politic == 5 ? 'moderate'
    : politic < 10 ? 'conservative'
    : 'ungoverned';
  return `${description} (P${politic})`;
}

function formatCrimes(target: Target): string {
  const crimesSorted = target.crimes.toSorted((a, b) => b.accounts - a.accounts);
  const topCrimes = crimesSorted.length > 4 ? crimesSorted.slice(0, 3) : crimesSorted;
  const otherCrimesCount = crimesSorted.length - topCrimes.length;
  const accountsFormatted = topCrimes.map(({ accounts, crime }) => accounts > 1 ? `${accounts} accounts of ${crime}` : crime);
  const allCrimes = otherCrimesCount ? accountsFormatted.concat([`${otherCrimesCount} other crimes`]) : accountsFormatted;
  const joint = (allCrimes.length > 1 ? allCrimes.slice(0, -1).concat('and ' + [allCrimes[allCrimes.length-1]]) : allCrimes).join(', ');
  return joint;
}

function formatLocale(locale: string): string {
  if (locale === "Seedy maze of alleys") return "Seedy mazes of alleys";
  if (locale === "oasis") return "oases";
  if (locale === "hydroponics") return "hydroponics";
  if (locale.endsWith('ay')) return locale + 's';
  if (locale.endsWith('y')) return locale.substring(0, locale.length - 1) + "ies";
  if (locale.endsWith('x')) return locale + 'es';
  if (locale.endsWith('ch')) return locale + 'es';
  return locale + 's';
}

function formatLayingLowType(layingLowType: LayingLowType|null): string {
  if (!layingLowType) {
    return '';
  }
  if (layingLowType === 'Planet hop') {
    return 'planet hopping';
  }
  if (layingLowType === 'Safehouse') {
    return 'in a safehouse';
  }
  if (layingLowType === 'Plastik surgery') {
    return 'doing plastik surgery';
  }
  return layingLowType.toLowerCase();
}